import { serve } from "https://deno.land/std/http/server.ts";
import { openKv } from "https://deno.land/x/kv/mod.ts";

const kv = await openKv();

serve(async (req) => {
  const url = new URL(req.url);
  const { pathname, searchParams } = url;

  if (pathname === "/search" && req.method === "GET") {
    const userId = searchParams.get("userId");
    const filterParam = searchParams.get("filterParam");

    if (!userId || !filterParam) {
      return new Response("Missing userId or filterParam", { status: 400 });
    }

    const key = ['users', userId, filterParam];
    const result = await kv.get(key);

    if (result !== null) {
      return new Response(JSON.stringify(result), {
        headers: { "Content-Type": "application/json" },
      });
    } else {
      return new Response("No data found", { status: 404 });
    }
  }

  return new Response("Not Found", { status: 404 });
});